def check_status_file(status_path: Path, rq_name: str, validation_log: List[str]) -> bool:
    """
    Check that prerequisite RQ completed successfully.

    Returns:
        True if rq_results: status: success found, False otherwise
    """
    log(f"[CHECK] Checking {rq_name} status file...", validation_log)

    if not status_path.exists():
        log(f"[ERROR] Status file not found: {status_path}", validation_log)
        return False

    # Read status.yaml and search for completion indicators
    try:
        with open(status_path, 'r', encoding='utf-8') as f:
            content = f.read()

        # Check for multiple patterns - status.yaml formats vary between chapters
        # Pattern 1: rq_results: followed by status: success (multi-line)
        # Pattern 2: rq_results: success (single line)
        # Pattern 3: Just "rq_results: success" at start of line
        patterns = [
            r'rq_results:\s*success',  # Single line format
            r'rq_results:\s*\n\s*status:\s*success',  # Multi-line format
            r'^rq_results:\s*success'  # At start of line only
        ]

        found = False
        for pattern in patterns:
            if re.search(pattern, content, re.MULTILINE):
                found = True
                log(f"[PASS] {rq_name} status: success (pattern: {pattern})", validation_log)
                break

        if found:
            return True
        else:
            log(f"[WARNING] {rq_name}: rq_results pattern not found, checking for PLATINUM status", validation_log)
            # Check for PLATINUM certification (highest level, implies completion)
            if re.search(r'certification:\s*\n\s*status:\s*PLATINUM', content):
                log(f"[PASS] {rq_name} has PLATINUM certification (highest validation level)", validation_log)
                return True
            else:
                log(f"[ERROR] {rq_name} not complete - neither rq_results: success nor PLATINUM found", validation_log)
                log(f"[DEBUG] Searched for patterns: {patterns}", validation_log)
                return False

    except Exception as e:
        log(f"[ERROR] Failed to read status file: {e}", validation_log)
        return False

def locate_file(primary_path: Path, pattern: str, file_type: str, validation_log: List[str]) -> Path:
    """
    Locate data file, trying primary path first, then glob pattern.

    Returns:
        Path to file if found, None otherwise
    """
    log(f"[LOCATE] Searching for {file_type}...", validation_log)

    # Try primary path
    if primary_path.exists():
        log(f"[FOUND] Primary path: {primary_path}", validation_log)
        return primary_path

    # Try alternative pattern
    log(f"[INFO] Primary not found, trying pattern: {pattern}", validation_log)
    parent_dir = Path(pattern).parent
    pattern_str = Path(pattern).name

    matches = list(parent_dir.glob(pattern_str))
    if matches:
        found_path = matches[0]
        log(f"[FOUND] Alternative path: {found_path}", validation_log)
        if len(matches) > 1:
            log(f"[WARNING] Multiple matches found, using first: {[str(m) for m in matches]}", validation_log)
        return found_path

    log(f"[ERROR] File not found: {file_type}", validation_log)
    log(f"[ERROR]   Primary: {primary_path}", validation_log)
    log(f"[ERROR]   Pattern: {pattern}", validation_log)
    return None

def verify_file_structure(file_path: Path, expected: Dict, file_type: str, validation_log: List[str]) -> bool:
    """
    Load CSV file and verify columns and row count.

    Returns:
        True if structure matches, False otherwise
    """
    log(f"[VERIFY] Checking structure of {file_type}...", validation_log)

    try:
        # Load file
        df = pd.read_csv(file_path, encoding='utf-8')

        # Check columns
        actual_cols = df.columns.tolist()
        expected_cols = expected["columns"]

        if actual_cols != expected_cols:
            log(f"[ERROR] Column mismatch for {file_type}", validation_log)
            log(f"[ERROR]   Expected: {expected_cols}", validation_log)
            log(f"[ERROR]   Actual: {actual_cols}", validation_log)
            return False

        # Check row count (allow 10% tolerance)
        actual_rows = len(df)
        expected_rows = expected["rows"]
        tolerance = 0.1 * expected_rows

        if abs(actual_rows - expected_rows) > tolerance:
            log(f"[ERROR] Row count mismatch for {file_type}", validation_log)
            log(f"[ERROR]   Expected: ~{expected_rows} rows", validation_log)
            log(f"[ERROR]   Actual: {actual_rows} rows", validation_log)
            return False

        log(f"[PASS] {file_type}: {actual_rows} rows, {len(actual_cols)} columns", validation_log)
        log(f"[INFO]   Columns: {actual_cols}", validation_log)

        # Check for missing data
        missing_counts = df.isnull().sum()
        if missing_counts.any():
            log(f"[WARNING] Missing data detected in {file_type}:", validation_log)
            for col, count in missing_counts[missing_counts > 0].items():
                pct = (count / len(df)) * 100
                log(f"[WARNING]   {col}: {count} missing ({pct:.1f}%)", validation_log)

        return True

    except Exception as e:
        log(f"[ERROR] Failed to verify {file_type}: {e}", validation_log)
        return False

